+/// Query used by [`LinkStore::search`] and [`LinkStore::count`].
+#[derive(Clone, Debug, Default, PartialEq, Eq)]
+pub struct LinkStoreQuery {
+    id: Option<LinkId>,
+    references: Option<Vec<LinkId>>,
+    link_type: Option<LinkType>,
+    term: Option<String>,
+    language: Option<String>,
+    named: Option<bool>,
