+#[cfg(feature = "doublets")]
+fn read_u8(bytes: &[u8], cursor: &mut usize) -> Result<u8, StorageError> {
+    let value = *read_bytes(bytes, cursor, 1)?
+        .first()
+        .expect("one byte was requested");
+    Ok(value)
