+                    "quasiquote placeholder is empty".to_string(),
+                ));
+            }
+            parts.push(TemplatePart::Placeholder(name));
+            rest = &after_open[end + 2..];
+        }
+        if !rest.is_empty() {
+            parts.push(TemplatePart::Literal(rest.to_string()));
+        }
+        if parts.is_empty() {
+            parts.push(TemplatePart::Literal(source));
+        }
+        Ok(Self { parts })
