+fn point_after_text(start: Point, text: &str) -> Point {
+    let mut row = start.row();
+    let mut column = start.column();
+    for byte in text.bytes() {
+        if byte == b'\n' {
+            row += 1;
+            column = 0;
+        } else {
+            column += 1;
+        }
+    }
+    Point::new(row, column)
+}
